def jwks_fetcher_from_url(jwks_url: str, timeout_seconds: float = 3.0) -> Callable[[], Dict[str, Any]]:
    if not isinstance(jwks_url, str) or not jwks_url:
        raise ValueError("jwks_url must be a non-empty string.")
    if not jwks_url.lower().startswith("https://"):
        raise ValueError("jwks_url must be https:// for security.")

    def fetch() -> Dict[str, Any]:
        import urllib.request

        req = urllib.request.Request(jwks_url, headers={"Accept": "application/json"})
        with urllib.request.urlopen(req, timeout=timeout_seconds) as resp:
            data = resp.read()
        return json.loads(data.decode("utf-8"))

    return fetch


def create_default_jwt_wrapper_from_env(
    *,
    internal_hs_secret_env: str = "JWT_INTERNAL_HS_SECRET",
    public_rs_pubkey_env: str = "JWT_PUBLIC_RS256_PUBKEY",
    public_jwks_url_env: str = "JWT_PUBLIC_JWKS_URL",
    internal_issuer_env: str = "JWT_INTERNAL_ISSUER",
    public_issuer_env: str = "JWT_PUBLIC_ISSUER",
    internal_audience_env: str = "JWT_INTERNAL_AUDIENCE",
    public_audience_env: str = "JWT_PUBLIC_AUDIENCE",
    leeway_seconds: int = 30,
) -> JWTAuthWrapper:
    internal_secret = os.getenv(internal_hs_secret_env)
    public_pubkey = os.getenv(public_rs_pubkey_env)
    public_jwks_url = os.getenv(public_jwks_url_env)

    internal_issuer = os.getenv(internal_issuer_env) or None
    public_issuer = os.getenv(public_issuer_env) or None

    internal_aud = os.getenv(internal_audience_env) or None
    public_aud = os.getenv(public_audience_env) or None

    sources: Dict[str, Dict[str, Any]] = {}

    if internal_secret:
        sources["internal_hs256"] = {
            "algs": ["HS256"],
            "hs_secret": internal_secret,
            "issuer": internal_issuer,
            "audience": internal_aud,
        }

    if public_pubkey:
        sources["public_rs256_static"] = {
            "algs": ["RS256"],
            "rs_public_key": public_pubkey,
            "issuer": public_issuer,
            "audience": public_aud,
        }

    if public_jwks_url:
        provider = RS256JWKSKeyProvider(jwks_fetcher=jwks_fetcher_from_url(public_jwks_url), cache_ttl_seconds=300)
        sources["public_rs256_jwks"] = {
            "algs": ["RS256"],
            "key_provider": provider,
            "issuer": public_issuer,
            "audience": public_aud,
        }

    if not sources:
        raise ValueError("No JWT sources configured from environment.")

    return JWTAuthWrapper(
        sources=sources,
        leeway_seconds=leeway_seconds,
        require_exp=True,
        require_iat=False,
        require_nbf=False,
        allowed_algs=["HS256", "RS256"],
    )


